mapper.update:
update CHome_Furniture_Power
set power_value = #{v},
    update_time = #{updateTime}
where device_power_id = #{deviceId}
  and power_name = #{n}

mapper.select:
select power_id, device_power_id, power_name, power_value, unit, power_type, operation_code, update_time
from CHome_Furniture_Power
where device_power_id = #{deviceId}
  and power_name = #{powerName}
